<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Ubuntu Desktop</title>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }
  html, body { height: 100%; overflow: hidden; }
  body {
    font-family: "Ubuntu", "Segoe UI", "Noto Sans", sans-serif;
    color: #eee;
    user-select: none;
  }

  /* ---------- Desktop ---------- */
  #desktop {
    position: fixed;
    inset: 0;
    background:
      radial-gradient(ellipse at 70% 20%, rgba(233,84,32,.35), transparent 55%),
      radial-gradient(ellipse at 20% 85%, rgba(119,33,111,.5), transparent 60%),
      linear-gradient(135deg, #2c001e 0%, #4a1440 45%, #77216f 75%, #a33c6d 100%);
    overflow: hidden;
  }

  /* ---------- Top bar ---------- */
  #topbar {
    position: absolute;
    top: 0; left: 0; right: 0;
    height: 30px;
    background: rgba(20, 18, 24, .92);
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0 14px;
    font-size: 13px;
    z-index: 5000;
    box-shadow: 0 1px 4px rgba(0,0,0,.4);
  }
  #topbar .tb-left { font-weight: 600; }
  #topbar .tb-right { display: flex; gap: 10px; opacity: .85; }

  /* ---------- Dock / taskbar ---------- */
  #taskbar {
    position: absolute;
    left: 0;
    top: 30px;
    bottom: 0;
    width: 68px;
    background: rgba(20, 18, 24, .82);
    backdrop-filter: blur(6px);
    display: flex;
    flex-direction: column;
    align-items: center;
    padding-top: 12px;
    gap: 12px;
    z-index: 4000;
    box-shadow: 1px 0 6px rgba(0,0,0,.35);
  }
  .launcher {
    width: 52px;
    height: 52px;
    border: none;
    border-radius: 12px;
    cursor: pointer;
    background: rgba(255,255,255,.06);
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    gap: 2px;
    color: #eee;
    font-size: 9px;
    transition: background .15s, transform .1s;
  }
  .launcher:hover { background: rgba(255,255,255,.16); }
  .launcher:active { transform: scale(.94); }
  .launcher .icon { font-size: 24px; line-height: 1; }

  /* ---------- Windows ---------- */
  .app-window {
    position: absolute;
    min-width: 360px;
    min-height: 240px;
    width: 560px;
    height: 400px;
    background: #2b2b33;
    border-radius: 10px;
    box-shadow: 0 12px 40px rgba(0,0,0,.55), 0 0 0 1px rgba(255,255,255,.08);
    display: flex;
    flex-direction: column;
    overflow: hidden;
    z-index: 100;
  }
  .app-window.hidden { display: none; }

  .titlebar {
    height: 36px;
    flex: 0 0 36px;
    background: linear-gradient(#3a3a44, #30303a);
    display: flex;
    align-items: center;
    padding: 0 8px 0 14px;
    font-size: 13px;
    font-weight: 600;
    cursor: grab;
    border-bottom: 1px solid rgba(0,0,0,.4);
  }
  .titlebar:active { cursor: grabbing; }
  .titlebar .title { flex: 1; pointer-events: none; }
  .win-close {
    width: 22px;
    height: 22px;
    border: none;
    border-radius: 50%;
    background: #e95420;
    color: #fff;
    font-size: 13px;
    line-height: 1;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
  }
  .win-close:hover { background: #ff6a35; }

  .win-body {
    flex: 1;
    display: flex;
    flex-direction: column;
    min-height: 0;
    background: #24242b;
  }

  /* ---------- Files app ---------- */
  #files-toolbar {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 8px 10px;
    background: #2f2f38;
    border-bottom: 1px solid rgba(0,0,0,.35);
  }
  #files-up {
    border: none;
    background: rgba(255,255,255,.1);
    color: #eee;
    border-radius: 6px;
    padding: 4px 12px;
    cursor: pointer;
    font-size: 14px;
  }
  #files-up:hover { background: rgba(255,255,255,.2); }
  #files-path {
    flex: 1;
    background: #1d1d23;
    border-radius: 6px;
    padding: 5px 10px;
    font-family: "Ubuntu Mono", Consolas, monospace;
    font-size: 13px;
    color: #cfcfd6;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
  }
  #files-list {
    flex: 1;
    overflow-y: auto;
    padding: 10px;
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(96px, 1fr));
    gap: 6px;
    align-content: start;
  }
  .fs-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 4px;
    padding: 10px 4px;
    border-radius: 8px;
    cursor: default;
    text-align: center;
    font-size: 12px;
    word-break: break-all;
  }
  .fs-item:hover { background: rgba(255,255,255,.08); }
  .fs-item .fs-icon { font-size: 30px; line-height: 1; pointer-events: none; }
  .fs-empty {
    grid-column: 1 / -1;
    opacity: .5;
    font-size: 13px;
    padding: 20px;
    text-align: center;
  }

  /* ---------- Notepad app ---------- */
  #tabs {
    display: flex;
    align-items: center;
    gap: 4px;
    padding: 6px 8px 0 8px;
    background: #2f2f38;
    overflow-x: auto;
    flex: 0 0 auto;
  }
  .tab {
    padding: 6px 12px;
    background: #24242b;
    border-radius: 8px 8px 0 0;
    font-size: 12px;
    cursor: pointer;
    white-space: nowrap;
    display: flex;
    align-items: center;
    gap: 8px;
    opacity: .65;
    max-width: 160px;
  }
  .tab .tab-label {
    overflow: hidden;
    text-overflow: ellipsis;
    pointer-events: none;
  }
  .tab.active {
    background: #1d1d23;
    opacity: 1;
    box-shadow: inset 0 2px 0 #e95420;
  }
  .tab .tab-x {
    opacity: .6;
    font-size: 11px;
    padding: 0 2px;
  }
  .tab .tab-x:hover { opacity: 1; color: #ff8060; }
  #new-tab {
    border: none;
    background: rgba(255,255,255,.1);
    color: #eee;
    border-radius: 6px;
    width: 26px;
    height: 26px;
    font-size: 16px;
    cursor: pointer;
    flex: 0 0 auto;
    margin-bottom: 4px;
  }
  #new-tab:hover { background: rgba(255,255,255,.2); }
  #editor {
    flex: 1;
    width: 100%;
    min-height: 0;
    resize: none;
    border: none;
    outline: none;
    background: #1d1d23;
    color: #e8e8ee;
    font-family: "Ubuntu Mono", Consolas, monospace;
    font-size: 14px;
    line-height: 1.5;
    padding: 12px 14px;
    user-select: text;
  }

  /* scrollbars */
  ::-webkit-scrollbar { width: 8px; height: 8px; }
  ::-webkit-scrollbar-thumb { background: rgba(255,255,255,.18); border-radius: 4px; }
  ::-webkit-scrollbar-track { background: transparent; }
</style>
</head>
<body>
<div id="desktop">
  <div id="topbar">
    <span class="tb-left">Activities</span>
    <span class="tb-center" id="clock">--:--</span>
    <span class="tb-right"><span>🔊</span><span>📶</span><span>🔋</span></span>
  </div>

  <div id="taskbar">
    <button id="open-files" class="launcher" title="Files">
      <span class="icon">📁</span><span>Files</span>
    </button>
    <button id="open-notepad" class="launcher" title="Notepad">
      <span class="icon">📝</span><span>Notepad</span>
    </button>
  </div>

  <!-- Files window -->
  <div id="files-window" class="app-window hidden" style="left:140px; top:80px;">
    <div class="titlebar">
      <span class="title">📁 Files</span>
      <button class="win-close" title="Close">✕</button>
    </div>
    <div class="win-body">
      <div id="files-toolbar">
        <button id="files-up" title="Up one level">⬆</button>
        <div id="files-path">/</div>
      </div>
      <div id="files-list"></div>
    </div>
  </div>

  <!-- Notepad window -->
  <div id="notepad-window" class="app-window hidden" style="left:260px; top:140px;">
    <div class="titlebar">
      <span class="title">📝 Notepad</span>
      <button class="win-close" title="Close">✕</button>
    </div>
    <div class="win-body">
      <div id="tabs"></div>
      <textarea id="editor" spellcheck="false" placeholder="Start typing…"></textarea>
    </div>
  </div>
</div>

<script>
(function () {
  "use strict";

  /* ================= Clock ================= */
  var clock = document.getElementById("clock");
  function tick() {
    var d = new Date();
    clock.textContent = d.toLocaleDateString(undefined, { month: "short", day: "numeric" }) +
      "  " + d.toLocaleTimeString(undefined, { hour: "2-digit", minute: "2-digit" });
  }
  tick();
  setInterval(tick, 10000);

  /* ================= Window management ================= */
  var zCounter = 200;

  function bringToFront(win) {
    zCounter += 1;
    win.style.zIndex = zCounter;
  }

  function setupWindow(win) {
    var titlebar = win.querySelector(".titlebar");
    var closeBtn = win.querySelector(".win-close");

    win.addEventListener("mousedown", function () { bringToFront(win); });

    closeBtn.addEventListener("click", function (e) {
      e.stopPropagation();
      win.classList.add("hidden");
    });

    // Dragging
    var dragging = false, offX = 0, offY = 0;
    titlebar.addEventListener("mousedown", function (e) {
      if (e.target === closeBtn) return;
      dragging = true;
      var rect = win.getBoundingClientRect();
      offX = e.clientX - rect.left;
      offY = e.clientY - rect.top;
      e.preventDefault();
    });
    document.addEventListener("mousemove", function (e) {
      if (!dragging) return;
      var x = Math.max(0, Math.min(e.clientX - offX, window.innerWidth - 80));
      var y = Math.max(30, Math.min(e.clientY - offY, window.innerHeight - 40));
      win.style.left = x + "px";
      win.style.top = y + "px";
    });
    document.addEventListener("mouseup", function () { dragging = false; });
  }

  var filesWindow = document.getElementById("files-window");
  var notepadWindow = document.getElementById("notepad-window");
  setupWindow(filesWindow);
  setupWindow(notepadWindow);

  document.getElementById("open-files").addEventListener("click", function () {
    filesWindow.classList.remove("hidden");
    bringToFront(filesWindow);
    renderFiles();
  });
  document.getElementById("open-notepad").addEventListener("click", function () {
    notepadWindow.classList.remove("hidden");
    bringToFront(notepadWindow);
    renderTabs();
  });

  /* ================= Files app ================= */
  // Fake filesystem: objects = folders, strings = files (content unused).
  var FS = {
    bin: { bash: "", cat: "", cp: "", ls: "", mkdir: "", mv: "", rm: "", sh: "", grep: "" },
    boot: { "vmlinuz-6.8.0-generic": "", "initrd.img-6.8.0-generic": "", grub: { "grub.cfg": "" } },
    dev: { null: "", zero: "", random: "", sda: "", tty0: "" },
    etc: {
      "hostname": "ubuntu-desktop",
      "hosts": "127.0.0.1 localhost",
      "fstab": "",
      "passwd": "",
      "os-release": "",
      apt: { "sources.list": "" },
      ssh: { "sshd_config": "" }
    },
    home: {
      user: {
        Documents: {
          "notes.txt": "",
          "resume.pdf": "",
          projects: { "todo.md": "", "ideas.txt": "" }
        },
        Downloads: { "ubuntu-24.04.iso": "", "photo.zip": "" },
        Pictures: { "wallpaper.png": "", "screenshot-2026.png": "", Vacation: { "beach.jpg": "" } },
        Music: {},
        Videos: {},
        ".bashrc": "",
        ".profile": ""
      }
    },
    lib: { "x86_64-linux-gnu": { "libc.so.6": "" } },
    opt: {},
    proc: { cpuinfo: "", meminfo: "", uptime: "" },
    root: {},
    tmp: {},
    usr: {
      bin: { python3: "", vim: "", gcc: "", curl: "", git: "" },
      lib: {},
      local: { bin: {} },
      share: { doc: {}, man: {} }
    },
    var: {
      log: { "syslog": "", "auth.log": "", "kern.log": "" },
      cache: { apt: {} },
      www: { html: { "index.html": "" } },
      tmp: {}
    }
  };

  var currentPath = []; // array of segments; [] = root

  function getNode(pathArr) {
    var node = FS;
    for (var i = 0; i < pathArr.length; i++) {
      if (node && typeof node === "object") node = node[pathArr[i]];
      else return null;
    }
    return node;
  }

  var filesPathEl = document.getElementById("files-path");
  var filesListEl = document.getElementById("files-list");

  function renderFiles() {
    var node = getNode(currentPath);
    if (!node || typeof node !== "object") { currentPath = []; node = FS; }

    filesPathEl.textContent = "/" + currentPath.join("/");

    filesListEl.innerHTML = "";
    var names = Object.keys(node).sort(function (a, b) {
      var aDir = typeof node[a] === "object", bDir = typeof node[b] === "object";
      if (aDir !== bDir) return aDir ? -1 : 1;
      return a.localeCompare(b);
    });

    if (names.length === 0) {
      var empty = document.createElement("div");
      empty.className = "fs-empty";
      empty.textContent = "This folder is empty";
      filesListEl.appendChild(empty);
      return;
    }

    names.forEach(function (name) {
      var isDir = typeof node[name] === "object";
      var item = document.createElement("div");
      item.className = "fs-item";
      item.dataset.dir = isDir ? "1" : "0";

      var icon = document.createElement("span");
      icon.className = "fs-icon";
      icon.textContent = isDir ? "📁" : "📄";

      var label = document.createElement("span");
      label.textContent = name;

      item.appendChild(icon);
      item.appendChild(label);

      if (isDir) {
        item.addEventListener("dblclick", function () {
          currentPath.push(name);
          renderFiles();
        });
      }
      filesListEl.appendChild(item);
    });
  }

  document.getElementById("files-up").addEventListener("click", function () {
    if (currentPath.length > 0) {
      currentPath.pop();
      renderFiles();
    }
  });

  renderFiles();

  /* ================= Notepad app ================= */
  var STORAGE_KEY = "ubuntu-notepad-v1";
  var tabsEl = document.getElementById("tabs");
  var editorEl = document.getElementById("editor");

  var state = loadState();

  function loadState() {
    try {
      var raw = localStorage.getItem(STORAGE_KEY);
      if (raw) {
        var parsed = JSON.parse(raw);
        if (parsed && Array.isArray(parsed.tabs) && parsed.tabs.length > 0) {
          if (typeof parsed.active !== "number" ||
              parsed.active < 0 || parsed.active >= parsed.tabs.length) {
            parsed.active = 0;
          }
          parsed.nextId = parsed.nextId || (parsed.tabs.length + 1);
          return parsed;
        }
      }
    } catch (e) { /* corrupted storage — start fresh */ }
    return {
      tabs: [{ id: 1, title: "Untitled 1", content: "" }],
      active: 0,
      nextId: 2
    };
  }

  function saveState() {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
    } catch (e) { /* storage full or unavailable */ }
  }

  function renderTabs() {
    tabsEl.innerHTML = "";
    state.tabs.forEach(function (tab, i) {
      var el = document.createElement("div");
      el.className = "tab" + (i === state.active ? " active" : "");

      var label = document.createElement("span");
      label.className = "tab-label";
      label.textContent = tab.title;
      el.appendChild(label);

      if (state.tabs.length > 1) {
        var x = document.createElement("span");
        x.className = "tab-x";
        x.textContent = "✕";
        x.title = "Close tab";
        x.addEventListener("click", function (e) {
          e.stopPropagation();
          state.tabs.splice(i, 1);
          if (state.active >= state.tabs.length) state.active = state.tabs.length - 1;
          else if (i < state.active) state.active -= 1;
          saveState();
          renderTabs();
        });
        el.appendChild(x);
      }

      el.addEventListener("click", function () {
        state.active = i;
        saveState();
        renderTabs();
      });

      tabsEl.appendChild(el);
    });

    var newBtn = document.createElement("button");
    newBtn.id = "new-tab";
    newBtn.title = "New tab";
    newBtn.textContent = "+";
    newBtn.addEventListener("click", function () {
      state.tabs.push({ id: state.nextId, title: "Untitled " + state.nextId, content: "" });
      state.nextId += 1;
      state.active = state.tabs.length - 1;
      saveState();
      renderTabs();
      editorEl.focus();
    });
    tabsEl.appendChild(newBtn);

    editorEl.value = state.tabs[state.active].content;
  }

  editorEl.addEventListener("input", function () {
    state.tabs[state.active].content = editorEl.value;
    saveState();
  });

  renderTabs();
})();
</script>
</body>
</html>
